// @ts-nocheck
import ExtensionPage from 'flarum/admin/components/ExtensionPage';
import AdminNav from './AdminNav';
import PointsRulesPanel from './PointsRulesPanel';
import UsersPointsPanel from './UsersPointsPanel';
import AvatarDecorationsPanel from './AvatarDecorationsPanel';
import NameDecorationsPanel from './NameDecorationsPanel';
import AutoGroupTiersPanel from './AutoGroupTiersPanel';
import ManualAwardPanel from './ManualAwardPanel';
export default class PointSystemSettingsPage extends ExtensionPage {
  content() {
    const tab = m.route.param('tab') || 'rules';
    let child;
    switch (tab) {
      case 'users':
        child = m(UsersPointsPanel, null);
        break;
      case 'avatar':
        child = m(AvatarDecorationsPanel, null);
        break;
      case 'name':
        child = m(NameDecorationsPanel, null);
        break;
      case 'groups':
        child = m(AutoGroupTiersPanel, null);
        break;
      case 'manual':
        child = m(ManualAwardPanel, null);
        break;
      default:
        child = m(PointsRulesPanel, {
          page: this
        });
    }
    return m("div", {
      className: "ExtensionPage-settings PointSystemAdmin"
    }, AdminNav(tab), m("div", {
      className: "container PointSystemAdmin-body"
    }, child));
  }
}
flarum.reg.add('ramon-point-system', 'admin/components/PointSystemSettingsPage', PointSystemSettingsPage);